// Time:  O(n)
// Space: O(1)

// string
class Solution {
public:
    int vowelStrings(vector<string>& words, int left, int right) {
        static const unordered_set<int> VOWELS = {'a', 'e', 'i', 'o', 'u'};

        int result = 0;
        for (int i = left; i <= right; ++i) {
            if (VOWELS.count(words[i].front()) && VOWELS.count(words[i].back())) {
                ++result;
            }
        }
        return result;
    }
};

# Time:  O(n)
# Space: O(1)

# string
class Solution(object):
    def vowelStrings(self, words, left, right):
        """
        :type words: List[str]
        :type left: int
        :type right: int
        :rtype: int
        """
        VOWELS = {'a', 'e', 'i', 'o', 'u'}
        return sum(words[i][0] in VOWELS and words[i][-1] in VOWELS for i in xrange(left, right+1))
